                                                                                                                                                                                    def st_dataframe_compat(df, *args, **kwargs):
                                                                                                                                                                                        """Совместимая обёртка для st.dataframe(width='stretch' для Streamlit 1.58+)"""
                                                                                                                                                                                        kwargs.pop('use_container_width', None)
