                                                                                                                                                                                                                                                                                                                                                                                                class DataCorruptionError(AutoPartsException):
                                                                                                                                                                                                                                                                                                                                                                                                    def __init__(self, message: str, file_path: Optional[Path] = None, checksum: Optional[str] = None):
                                                                                                                                                                                                                                                                                                                                                                                                        self.file_path = file_path
